var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하아아앗-!!","JPN":"はあああーっ！！","ENG":"Haaaaa!!!!","TWN":"哈啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"저 녀석. 연무장 때랑은 뭔가 다른 것 같지 않아?","JPN":"あいつ、訓練場の時とはなんか違うと思わないか？","ENG":"Hey, doesn't she seem different from how she was back in the training hall?","TWN":"那傢伙。和在演武場時有什麼不一樣，不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"네 눈은 옹이구멍이냐? 검을 휘두르는 동작 자체가 달라졌잖아.","JPN":"あんたの目は節穴か？　剣を振り回す動作自体が以前とは違っているじゃないか。","ENG":"Are your eyes just for show? Even the way she swings her sword is completely different.","TWN":"你的眼睛是木頭做的嗎？揮劍的動作都已經不一樣了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"그레이스 경이 봐주셨다지만 며칠 만에 저렇게 되다니… 나 같은 범재는 벽을 느끼는구만.","JPN":"グレース卿が鍛えてくださったとは言え、数日であんなになるなんて……俺みたいな凡才は壁を感じるなあ。","ENG":"Dame Grace may be training her, but this kind of improvement in just a few days? Makes someone like me feel hopeless.","TWN":"雖然是經過葛瑞絲小姐的訓練，但幾天之內就能變成這樣……像我這樣的凡人真是感受到差距了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"그래서, 지켜만 보게?","JPN":"で、ただ見てるだけなのか？","ENG":"So, what, you just gonna sit there?","TWN":"所以，就這樣看著嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"설마. 오늘은 누가 더 괴수를 많이 때려잡나 승부다!","JPN":"まさか。今日は誰が怪獣をもっと多く倒せるか、勝負だ！","ENG":"Heck no. Let's make it a bet to see who slays more monsters!","TWN":"怎麼可能，來看看今天誰殺比較多怪！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"뒤처진 녀석들의 저녁은, 아주 조촐할 줄 알아!","JPN":"少ないやつらの夕飯は、肉抜きだ。","ENG":"The loser gets the smallest portion for dinner!","TWN":"輸的人晚餐就只能用醬油拌飯！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"지칠 법한 연속된 전투 속에서도 단 한 명의 존재가 병사들의 사기를 북돋우고 있다.","JPN":"うんざりするほどに続く戦闘の中でも、たった一人の存在が兵士の士気を上げている。","ENG":"Even after constant battles, just one person is enough to lift the entire unit's morale.","TWN":"在令人疲憊的連續戰鬥中，只有一個人能夠激勵士兵們的士氣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그레이스 경의 부재가 전세에 큰 영향을 끼치지 않을까 싶었으나… 기우였군.","JPN":"グレース卿の不在が戦況に影響するのではと思ったが……杞憂だったな。","ENG":"I thought Dame Grace's absence would tip the scales... but I was clearly wrong.","TWN":"我原以為葛瑞絲卿的缺席會對戰局產生重大影響……看來是杞人憂天了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"페론 경! 괴수들이 물러가기 시작합니다!","JPN":"ペロン卿！　怪獣が退き始めています！","ENG":"Sir Ferron! The monsters are retreating!","TWN":"費隆卿！怪獸們開始撤退了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"제가 진입할 테니 좌익과 우익을 선회하세요! 빠져나온 비행형은 딜란 경이 맡습니다!","JPN":"私が突入しますので、左翼と右翼は旋回してください！　抜け出た飛行型はディラン卿が担当してください！","ENG":"I'm heading in! Flank them from both sides! Sir Dylan, handle the fliers that broke away!","TWN":"我會加入，你們負責左翼和右翼的迂回！逃出來的飛行型由迪蘭負責！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전군, 돌격-!!","JPN":"全軍、突撃！！","ENG":"Knights, charge!","TWN":"全軍，出擊-！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"크아-! 설마 이번 원정이 이렇게 순조로울 줄이야!","JPN":"くうー！　まさか今回の遠征がここまで順調とは！","ENG":"Hah! Who would've thought this mission would actually go well?!","TWN":"哇-！ 沒想到這次遠征會如此順利！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"피해도 최소화하고 있으니, 어쩌면 다 같이 돌아가는 것도 꿈이 아니겠어!","JPN":"被害も最少限に抑えられているし、みんなで帰るのも夢ではないかもな！","ENG":"Minimal casualties too. Maybe, just maybe, we'll all make it back alive!","TWN":"既然已經將損失降到最低，也許大家一起回去也不是夢！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"예상보다 많이 살아남은 탓에 식량문제는 있지만 말이야, 하하!!","JPN":"予想より多く生き残っているせいで、食糧問題はあるけどな、はは！！","ENG":"Only problem now is food with more survivors than we planned for, haha!","TWN":"雖然比預想中活下來的人多會導致糧食問題，哈哈！！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇다고 채식이 말입니까? 싸울려면 고기를 먹어야죠!","JPN":"だからって野菜ばかり食べろっていうんですか！　戦うためには肉を食べないと！","ENG":"What, so we're going vegetarian now?! We need meat to fight!","TWN":"所以是要吃素嗎？不吃肉怎麼有體力作戰！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_AH"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"맞습니다! 연회도 아닌데 뭔 놈의 술만 이렇게 가져오셨어요?","JPN":"そうです！　宴会しに来たんじゃないのに、誰が酒ばっかりこんなに持ってきたんですか！","ENG":"Seriously! Why'd we bring so much booze and no food?","TWN":"沒錯！又不是宴會，怎麼帶了這麼多酒來？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"시끄러워, 인마! 토벌 수를 기준으로 저녁을 나누자고 한 게 누구인데?","JPN":"うるせえ！　討伐した数に応じて夕飯の量を決めようって言ったのはどこのどいつだ！","ENG":"Shut it! You're the one who said dinner would be based on monster kills!","TWN":"吵死了，混蛋！是誰提議根據殺怪數來分配晚餐的？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"나도 안주 없이 술만 먹고 있잖아! 부족하면 저기 가서 풀이나 뜯어 먹어!","JPN":"俺だってつまみなしで酒飲んでるんだ！　足りなかったらあそこで草でも食べてろ！","ENG":"I'm stuck drinking with nothing to eat too! If you're hungry, go chew on some grass!","TWN":"我也在沒有下酒菜只能喝酒！不夠的話就去那裡吃草吧！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"식사가 부족하시다면 제 음식을 나눠드리겠습니다.","JPN":"食事が足りないのでしたら、私の分をお分けします。","ENG":"If food is short, I'd be happy to share mine.","TWN":"如果你食物不夠，我可以分給你一些我的食物。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"다른 분들 말은 신경 쓰실 필요 없습니다. 식량배분조차 전쟁에선 중요한 요소니까요.","JPN":"他の方々の発言は気にする必要ありません。食糧分配も戦争では重要な要素ですから。","ENG":"No need to worry. Rationing's part of the fight too.","TWN":"不用在意其他人的話。在戰爭中，糧食分配也很重要。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"경께서 굶으면 크나큰 전력 손실인 만큼, 저희를 위한다면 배불리 먹고 힘을 비축해 두세요.","JPN":"卿が空腹だと大変な戦力損失になります。私たちのためにもお腹いっぱい食べて力を貯めてください。","ENG":"You're a key asset. If you go hungry, that's a loss for all of us. Do us a favor and eat your fill.","TWN":"你若是餓著肚子，那可是巨大的戰力損失。為了我們，請吃飽飯，儲備力量吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……예. 감사합니다, 페론 경.","JPN":"……はい、ありがとうございます、ペロン卿。","ENG":"...Understood. Thank you, Sir Ferron.","TWN":"……好的。謝謝你，費隆卿。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"하지만 식량문제는 사기와 직결되는 중요한 요소라는 것 또한 엄연한 사실.","JPN":"ですが、食糧問題は士気に繋がる重要な要素だということもまた事実です。","ENG":"Still, food shortage is no joke. It hits morale hard.","TWN":"但是糧食問題確實是與士氣直接相關的重要因素。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이렇게 된 이상, 제가 안줏거리가 될 즐거운 이야기를 해보겠습니다.","JPN":"こうなったら、私がつまみになりそうな面白い話をしましょう。","ENG":"So, how about I share a little story to go with the wine?","TWN":"既然如此，我就講個有趣的故事來當下酒菜吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"술 하니 고향에서 포도 농사를 하던 시기가 떠오르는군요. 마침 고향에서는 저희 농가에서 만든 포도 와인이 특히 인기였는데, 조금 설명하면 고조부님 시절부터 시작한 유서 깊은 사업으로-\xA0\xA0","JPN":"酒と言えば地元でブドウを育てていた時を思い出します。ちょうど故郷では私の農家で作ったワインが有名だったのですが、少し説明しますと高祖父時代から始まった由緒正しき事業で……\xA0\xA0","ENG":"This reminds me of back home, when we used to grow grapes. Our vineyard was known for its wine, you see. Goes back to my great-grandfather's day, a real legacy–\xA0\xA0","TWN":"說到酒，就讓我想起了在家鄉種葡萄的時光。正好在家鄉，我們農場釀造的葡萄酒特別受歡迎，簡單來說，這是從曾祖父時代開始的歷史悠久的事業——"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"빌어먹을! 술에 취해서인지 나도 모르게 저지르고 말았어!!","JPN":"くそ！　俺、酔っぱらってついやってしまったぞ！！","ENG":"Dammit! Maybe it's the booze, but I snapped and made it worse!!","TWN":"該死！我竟然酒醉誤事！！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"설교는 한 시간이지만 수다는 세 시간이야! 꿈이라고 착각하도록 위치라도 옮겨놓자고!!","JPN":"説教は1時間だけど、おしゃべりは3時間だ！　夢だと思うように位置を変えておこう！！","ENG":"His lectures take one hour, but his stories last three! Move him somewhere so he thinks this is a dream!","TWN":"講道是一小時，但閒聊是三小時！至少換個地方，讓人誤以為是在做夢！！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"에스테로사 경. 무슨 일이라도 있으신가요?","JPN":"エステロサ卿、どうかしましたか？","ENG":"Is something wrong, Dame Esterosa?","TWN":"艾斯特洛索。有什麼事情嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 가볍게 산책이라도 하고 오려고 합니다.","JPN":"いいえ。軽く散歩でもして来ようと思います。","ENG":"No. Just going for a short walk.","TWN":"不。我只是想輕鬆地散步一下。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"주변을 잠시 돌아볼 뿐이니, 저는 신경 쓰지 마시고 편히 쉬시죠.","JPN":"周辺を少し歩くだけですので、私のことは気にせずお休みください。","ENG":"I'm only having a quick look around. Please, make yourself comfortable.","TWN":"我只是去附近轉轉，你不用擔心，安心休息吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 일이시길래 그리 우수에 찬 눈빛을 하고 계십니까?","JPN":"どうしてそのような憂いを帯びた目をしていらっしゃるのですか？","ENG":"What's got you staring into the distance like that, Dame Esterosa?","TWN":"有什麼事情讓你露出如此憂傷的眼神呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경… 시간이 늦었는데, 쉬지 않으셔도 되겠습니까?","JPN":"グレース卿……遅い時間ですが、休まなくてもいいのですか？","ENG":"Dame Grace... It's late. Shouldn't you be resting?","TWN":"葛瑞絲小姐……時間已經很晚了，你不休息嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"병사들의 기분에 어울리는 것도 귀족으로서의 의무지요.","JPN":"兵士に付き合うのも貴族としての義務です。","ENG":"Blending in with the troops is part of a noble's duty too.","TWN":"迎合士兵們的心情也是貴族的義務呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"모처럼 달이 아름다운 밤이니, 저도 조금 우수에 차버렸답니다.","JPN":"せっかく月が綺麗な夜ですので、私も少し感傷に浸ってしまいました。","ENG":"And with the moon out like this, I got a bit sentimental myself.","TWN":"難得月色如此美麗的夜晚，我也不禁有些憂傷了呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"또 술을 드셨단 이야기로군요.","JPN":"またお酒を飲んだということですね。","ENG":"You've been drinking again, haven't you?","TWN":"又喝酒了吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 두 잔, 아니, 세 잔만 했답니다.","JPN":"ふふ。2杯、いいえ、3杯だけです。","ENG":"Haha. Just two, maybe three glasses.","TWN":"呵呵。只喝了兩杯，不，三杯而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"덕분에 경의 말동무가 될 기회 또한 얻었으니 이 어찌 기복이 아니겠습니까?","JPN":"おかげで卿のお話し相手になれるチャンスを手に入れたのですから、これもまた幸運なのではないでしょうか。","ENG":"But thanks to that, I get to enjoy your company. Isn't that lovely?","TWN":"因為這樣，我才有機會成為你的談話夥伴，這難道不是一種福氣嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그래서, 모처럼의 연회를 이리 혼자 보내려 하신 연유가 무엇인지요?","JPN":"それで、せっかくの宴会なのにこうして一人で過ごそうとしている理由はなんですか？","ENG":"So tell me, why are you spending this fine evening alone?","TWN":"所以，你為何要獨自度過這難得的宴會呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"잠시 기사단의 동료들을 떠올렸습니다.","JPN":"騎士団の仲間たちのことを思い出していました。","ENG":"I was thinking about the other knights... my old comrades.","TWN":"我暫時想起了騎士團的同伴們。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"책임을 등지고 떠난 저를, 여전히 동료라고 생각해줄지는 모르겠지만요.","JPN":"責任から目を背けて逃げた私を、変わらず仲間だと思ってくれるかはわかりませんが。","ENG":"I abandoned my duties. I don't know if they'd even still call me a comrade.","TWN":"我背棄了責任離開，不知道他們是否仍然把我當作同伴。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"인연이 소중하다면 다시 돌아가심은?","JPN":"大事な絆でしたら、再びお戻りになっては？","ENG":"If those bonds still matter to you, why not go back?","TWN":"如果緣分珍貴，那為何不再回去呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……모르겠습니다.","JPN":"……わかりません。","ENG":"...I don't know.","TWN":"……我不知道。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예전에는 아무렇지도 않게 해왔던 일들이 이제는 버겁게 느껴지는군요.","JPN":"昔は何とはなしにやってきたことが、今では辛く感じるんです。","ENG":"Things I used to do so easily now feel like a burden.","TWN":"以前輕鬆完成的事情，現在卻感到吃力了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어쩌면 무리해서 달려온 탓에 지쳐버린 걸지도 모르겠습니다.","JPN":"もしかしたら無理して走ってきたせいで、疲れてしまったのかもしれません。","ENG":"Maybe I've just burned myself out, chasing too hard for too long.","TWN":"或許是因為拼命奔跑而感到疲憊吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"평범함이 특별함의 연속이라는 것을 깨닫는 것은 비로소 무언가를 잃었을 때입니다.","JPN":"人は初めて何かを失った時、平凡な日常が特別の連続であったと気づきます。","ENG":"It's only when we lose the ordinary that we realize how precious it was.","TWN":"意識到平凡是特別的延續，往往是在失去某些東西的時候。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"때문에 대부분의 사람들은 자신의 평범함을 되찾는 것에 주력하나…….","JPN":"そのため、ほとんどの人は自分の日常を取り戻すことに集中しますが……","ENG":"Most people just want to get their normal back...","TWN":"因此，大多數人都專注於找回自己的平凡……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서는 잃어버린 것을 되찾는데 보다 집착하시는 것처럼 느껴지는군요.","JPN":"卿は失ったものを取り戻すことに執着しているように見えます。","ENG":"But you seem fixated on reclaiming what was lost.","TWN":"你似乎更執著於找回失去的東西。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무서울 정도로 속내를 읽으시네요.","JPN":"怖いほど心を読まれていますね。","ENG":"You see right through me. It's kind of terrifying.","TWN":"你真是可怕，居然能看透我的心思。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그야, 별의 인도자니까요.","JPN":"それは、星の導き手ですから。","ENG":"Well, I am the Star Guide.","TWN":"因為你是星之引導者啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"조디악 나이츠의 이전 세대는 유례없는 황금세대라 불리는 자들이었습니다.","JPN":"ゾディアックナイツの先代の騎士たちは、前例のない、黄金の世代と呼ばれていました。","ENG":"The previous generation of the Zodiac Knights were called the golden generation.","TWN":"十二宮騎士團的前一代被稱為史無前例的黃金世代。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그리고 제 오빠는 그런 기사단의 단장이었죠.","JPN":"そして私の兄はそんな騎士団の団長だったのです。","ENG":"And my brother led them as Captain.","TWN":"而我的哥哥就是那個騎士團的團長。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어린 마음에 비교당하는 것이 내심 분하면서도… 한편으로는 그런 오빠를 동경했습니다.","JPN":"幼な心に、比べられることを悔しく思いはしましたが……一方ではそんな兄に憧れていました。","ENG":"As a kid, I hated being compared to him... But deep down, I admired him.","TWN":"雖然我很討厭從小就被拿來和哥哥比較……但另一方面，我也很仰慕那樣的哥哥。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는, 그런 기사가 되고 싶었어요.","JPN":"私は、そういう騎士になりたかった。","ENG":"That's the kind of knight I wanted to become.","TWN":"我曾經想成為那樣的騎士。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그런 기사라고 함은 무엇인지요?","JPN":"そういう騎士とは何でしょうか？","ENG":"And what kind of knight was that?","TWN":"所謂的騎士精神是什麼呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경의 눈에 그의 완벽함만이 담겼다면 그와 같은 존재가 되기를 바랐을 겁니다.","JPN":"卿の目に彼の完璧な姿だけが見えていたのなら、彼のような存在になりたいと思ったでしょう。","ENG":"If you only saw his perfection, then of course you'd want to be like him.","TWN":"如果在大人的眼中只有他的完美，那麼他會希望成為那樣的存在。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"강함을 동경하는 것만이라면 전승 속 영웅의 이야기를 쫓았을 테고요.","JPN":"強さに憧れていただけなら、伝承の中の英雄譚を追い続けていたはずです。","ENG":"If it was strength you longed for, then you'd chase the legends of heroes.","TWN":"如果只是憧憬強大，我會追尋傳說中的英雄故事。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"에스텔. 이유 없는 여정에 몸을 맡기는 이는 없습니다.","JPN":"エステル。理由のない旅に身を委ねる人はいません。","ENG":"Esther. No one goes on a journey for no reason.","TWN":"艾斯特。沒有人會將自己置身於無意義的旅程中。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그리고 모든 여정은 거창한 목표가 아닌 사사로운 마음에서 비롯되지요.","JPN":"そしてすべての旅路は大層な目標ではなく、個人的な心情から始まります。","ENG":"And every journey begins not with some grand purpose, but with a simple desire.","TWN":"而所有的旅程都不是從宏偉的目標開始，而是源於細微的心意。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그것들은 비록 뒷전으로 밀릴지언정, 결코 잊어서는 아니 될 것입니다.","JPN":"それらはたとえ後回しになっても、決して忘れてはいけません。","ENG":"It may get buried later, but it's something you should never forget.","TWN":"那些事情即使被擱置，也絕不能忘記。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……어렵군요.","JPN":"……難しいですね。","ENG":"...That's difficult.","TWN":"……有點困難呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어려운 것이, 또한 가치 있는 법이죠.","JPN":"難しいものは、価値のあるものです。","ENG":"The things that matter are difficult.","TWN":"困難的事情，往往也是有價值的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 말씀하신 것이 무엇인지 조금은 알 것 같습니다.","JPN":"でも、何がおっしゃりたいのか、少しはわかるような気がします。","ENG":"Still, I think I'm beginning to understand.","TWN":"不過我大概能猜出來你在說些什麼了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제 나름대로 생각을 정리해볼 필요가 있겠군요.","JPN":"自分なりに考えをまとめる必要がありそうですね。","ENG":"I'll take some time to think things through.","TWN":"我需要整理一下自己的想法。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 이만 들어가겠습니다만, 그레이스 경은 어쩌시겠습니까?","JPN":"私はこれで失礼します。グレース卿はどうなさいますか？","ENG":"I'm heading back. What about you, Dame Grace?","TWN":"我要先回去了，你呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"먼저 들어가시지요. 저는 조금만 더 바람을 쐬겠습니다.","JPN":"お先にどうぞ。私はもう少し夜風に当たります。","ENG":"Go on ahead. I'll stay out a little longer.","TWN":"你先回去吧，我再吹會兒風。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예. 좋은 밤 되십시오, 그레이스 경.","JPN":"はい。おやすみなさい、グレース卿。","ENG":"All right. Good night, Dame Grace.","TWN":"是的。晚安，葛瑞絲小姐。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그럴듯하게 말해놓고, 정작 나 자신도 길을 헤매고 있구나.","JPN":"それらしいことを言っておいて、結局私も迷っているのね。","ENG":"I talk like I've got it all figured out, but I'm just as lost as anyone.","TWN":"說得頭頭是道，結果我自己也在迷路啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무책임하게 업을 떠맡기느냐, 모든 걸 포기하고 내려놓느냐.","JPN":"無責任に業を押しつけるか、すべてを諦めるか。","ENG":"Do I take on this burden or let it all go?","TWN":"是無責任地承擔工作，還是放棄一切放下。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……이제, 결정해야겠지.","JPN":"……もう決めるべきだわ。","ENG":"...Guess it's time to decide.","TWN":"……現在，是時候做出決定了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};